{"id": "kuhp_pasal_5", "pasal": "5", "bab": "BAB I - RUANG LINGKUP BERLAKUNYA KETENTUAN PERATURAN PERUNDANG-UNDANGAN PIDANA", "judul": "", "context": "Pasal 5
