{"id": "kuhp_pasal_516", "pasal": "516", "buku": "BUKU KEDUA - TINDAK PIDANA", "bab": "BAB XXVIII - TINDAK PIDANA TERHADAP KEPERCAYAAN DALAM MENJALANKAN USAHA", "bagian": "Bagian Kedua - Perbuatan Curang Pengurus atau Komisaris", "paragraf": "", "judul": "", "context": "Pasal 516
